package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetAllowMissingColumnNames_default() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_withAllowMissingColumnNames_true() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames();
        assertTrue(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_withAllowMissingColumnNames_false() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);
        assertFalse(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_preservesValue() {
        CSVFormat formatTrue = CSVFormat.DEFAULT.withAllowMissingColumnNames(true);
        assertTrue(formatTrue.getAllowMissingColumnNames());

        CSVFormat formatFalse = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);
        assertFalse(formatFalse.getAllowMissingColumnNames());
    }

    @Test
    void testSetAllowMissingColumnNamesUsingReflection() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        Field field = CSVFormat.class.getDeclaredField("allowMissingColumnNames");
        field.setAccessible(true);

        // CSVFormat is immutable, so we cannot change the field on the existing instance.
        // Instead, create a new instance with the field changed via reflection on a copy.

        // Create a new instance by copying DEFAULT fields
        CSVFormat newFormat = createCSVFormatWithAllowMissingColumnNames(format, true);
        assertTrue(newFormat.getAllowMissingColumnNames());

        newFormat = createCSVFormatWithAllowMissingColumnNames(format, false);
        assertFalse(newFormat.getAllowMissingColumnNames());
    }

    // Helper method to create a new CSVFormat instance with modified allowMissingColumnNames field
    private CSVFormat createCSVFormatWithAllowMissingColumnNames(CSVFormat baseFormat, boolean allowMissing) throws Exception {
        Field[] fields = CSVFormat.class.getDeclaredFields();
        // Collect all field values from baseFormat
        Object[] params = new Object[16];
        Class<?>[] paramTypes = new Class<?>[16];

        // The constructor parameters order from the source:
        // (char delimiter, Character quoteChar, QuoteMode quoteMode,
        // Character commentStart, Character escape, boolean ignoreSurroundingSpaces,
        // boolean ignoreEmptyLines, String recordSeparator, String nullString,
        // Object[] headerComments, String[] header, boolean skipHeaderRecord,
        // boolean allowMissingColumnNames, boolean ignoreHeaderCase, boolean trim,
        // boolean trailingDelimiter)

        // Get all needed fields by reflection
        Field delimiterField = CSVFormat.class.getDeclaredField("delimiter");
        Field quoteCharField = CSVFormat.class.getDeclaredField("quoteCharacter");
        Field quoteModeField = CSVFormat.class.getDeclaredField("quoteMode");
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        Field escapeCharacterField = CSVFormat.class.getDeclaredField("escapeCharacter");
        Field ignoreSurroundingSpacesField = CSVFormat.class.getDeclaredField("ignoreSurroundingSpaces");
        Field ignoreEmptyLinesField = CSVFormat.class.getDeclaredField("ignoreEmptyLines");
        Field recordSeparatorField = CSVFormat.class.getDeclaredField("recordSeparator");
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        Field headerCommentsField = CSVFormat.class.getDeclaredField("headerComments");
        Field headerField = CSVFormat.class.getDeclaredField("header");
        Field skipHeaderRecordField = CSVFormat.class.getDeclaredField("skipHeaderRecord");
        Field ignoreHeaderCaseField = CSVFormat.class.getDeclaredField("ignoreHeaderCase");
        Field trimField = CSVFormat.class.getDeclaredField("trim");
        Field trailingDelimiterField = CSVFormat.class.getDeclaredField("trailingDelimiter");

        delimiterField.setAccessible(true);
        quoteCharField.setAccessible(true);
        quoteModeField.setAccessible(true);
        commentMarkerField.setAccessible(true);
        escapeCharacterField.setAccessible(true);
        ignoreSurroundingSpacesField.setAccessible(true);
        ignoreEmptyLinesField.setAccessible(true);
        recordSeparatorField.setAccessible(true);
        nullStringField.setAccessible(true);
        headerCommentsField.setAccessible(true);
        headerField.setAccessible(true);
        skipHeaderRecordField.setAccessible(true);
        ignoreHeaderCaseField.setAccessible(true);
        trimField.setAccessible(true);
        trailingDelimiterField.setAccessible(true);

        params[0] = delimiterField.getChar(baseFormat);
        paramTypes[0] = char.class;

        params[1] = (Character) quoteCharField.get(baseFormat);
        paramTypes[1] = Character.class;

        params[2] = quoteModeField.get(baseFormat);
        paramTypes[2] = QuoteMode.class;

        params[3] = (Character) commentMarkerField.get(baseFormat);
        paramTypes[3] = Character.class;

        params[4] = (Character) escapeCharacterField.get(baseFormat);
        paramTypes[4] = Character.class;

        params[5] = ignoreSurroundingSpacesField.getBoolean(baseFormat);
        paramTypes[5] = boolean.class;

        params[6] = ignoreEmptyLinesField.getBoolean(baseFormat);
        paramTypes[6] = boolean.class;

        params[7] = (String) recordSeparatorField.get(baseFormat);
        paramTypes[7] = String.class;

        params[8] = (String) nullStringField.get(baseFormat);
        paramTypes[8] = String.class;

        params[9] = headerCommentsField.get(baseFormat);
        paramTypes[9] = Object[].class;

        params[10] = headerField.get(baseFormat);
        paramTypes[10] = String[].class;

        params[11] = skipHeaderRecordField.getBoolean(baseFormat);
        paramTypes[11] = boolean.class;

        params[12] = allowMissing;
        paramTypes[12] = boolean.class;

        params[13] = ignoreHeaderCaseField.getBoolean(baseFormat);
        paramTypes[13] = boolean.class;

        params[14] = trimField.getBoolean(baseFormat);
        paramTypes[14] = boolean.class;

        params[15] = trailingDelimiterField.getBoolean(baseFormat);
        paramTypes[15] = boolean.class;

        // Get the constructor
        java.lang.reflect.Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class, Character.class, QuoteMode.class,
                Character.class, Character.class, boolean.class,
                boolean.class, String.class, String.class,
                Object[].class, String[].class, boolean.class,
                boolean.class, boolean.class, boolean.class,
                boolean.class);

        constructor.setAccessible(true);

        return constructor.newInstance(params);
    }
}
